//! C ABI for `blitz-task-runtime`.
//!
//! Exposes [`run_with_udp`](crate::run_with_udp) and the `--blitz-info`
//! renderer to C and C++ wrapper executables. The wrappers `#include
//! "blitz_task_runtime.h"` (committed alongside this crate, regenerated by
//! `build.rs` via cbindgen) and link the staticlib variant of this crate.

use std::ffi::{c_char, CStr};
use std::ptr;
use std::sync::OnceLock;

use crate::{render_info_json, run_with_udp};

/// Result code returned by [`br_run_with_udp`].
#[repr(C)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BrRunResult {
    /// Task ran to completion and emitted a signed `done` datagram.
    BrRunOk = 0,
    /// UDP socket bind / send failed before or after the task.
    BrRunUdpError = 1,
    /// The task returned a [`TaskError`](blitz_task::TaskError).
    BrRunTaskError = 2,
    /// One or both pointer arguments were null.
    BrRunInvalidArg = 3,
}

/// Drive a `BlitzTask*` (defined in `blitz_task.h`) over the UDP wire
/// protocol, signing the final metrics with the supplied 32-byte
/// Ed25519 key.
///
/// **Ownership.** This function does *not* free `task` — the caller
/// remains responsible for calling `blitz_task_free` once
/// `br_run_with_udp` returns.
///
/// # Safety
///
/// - `task` must be a valid `BlitzTask*` returned from a task library's
///   constructor.
/// - `signing_key` must point to 32 readable bytes.
/// - This function is single-threaded; do not call concurrently on the
///   same `BlitzTask*`.
#[no_mangle]
pub unsafe extern "C" fn br_run_with_udp(
    task: *mut CBlitzTask,
    port: u16,
    signing_key: *const u8,
) -> BrRunResult {
    if task.is_null() || signing_key.is_null() {
        return BrRunResult::BrRunInvalidArg;
    }
    let key_slice = std::slice::from_raw_parts(signing_key, 32);
    let mut key = [0u8; 32];
    key.copy_from_slice(key_slice);

    let mut wrapper = CTaskAdapter {
        task,
        info: OnceLock::new(),
    };

    match run_with_udp(&mut wrapper, port, &key) {
        Ok(_) => BrRunResult::BrRunOk,
        Err(crate::UdpRunError::Task(_)) => BrRunResult::BrRunTaskError,
        Err(_) => BrRunResult::BrRunUdpError,
    }
}

/// Render a `BlitzTask*`'s `--blitz-info` payload into the caller-supplied
/// buffer. Writes a null-terminated UTF-8 string. Returns the number of
/// bytes written **excluding** the null terminator, or `(size_t)-1` if
/// `buf_len` is too small (the caller can retry with a larger buffer).
///
/// # Safety
///
/// - `task` must be a valid `BlitzTask*`.
/// - `buf` must point to `buf_len` writeable bytes (may be `NULL` only when
///   `buf_len == 0`, in which case the function returns the required size).
#[no_mangle]
pub unsafe extern "C" fn br_render_info(
    task: *mut CBlitzTask,
    buf: *mut c_char,
    buf_len: usize,
) -> isize {
    if task.is_null() {
        return -1;
    }
    let wrapper = CTaskAdapter {
        task,
        info: OnceLock::new(),
    };
    let json = render_info_json(&wrapper);
    let bytes = json.as_bytes();
    let needed = bytes.len();

    if buf.is_null() || buf_len == 0 {
        return needed as isize;
    }
    if buf_len < needed + 1 {
        return -1;
    }
    ptr::copy_nonoverlapping(bytes.as_ptr(), buf as *mut u8, needed);
    *buf.add(needed) = 0; // null terminate
    needed as isize
}

// ── C task adapter ───────────────────────────────────────────────────────────

/// Opaque forward declaration that mirrors `BlitzTask` from `blitz_task.h`.
/// cbindgen renders this as `typedef struct CBlitzTask CBlitzTask;`. The
/// header `blitz_task_runtime.h` then `#include "blitz_task.h"` and typedef
/// `BlitzTask` → `CBlitzTask`.
#[repr(C)]
pub struct CBlitzTask {
    _private: [u8; 0],
}

// Wraps a foreign `BlitzTask*` so the Rust runtime can drive it through
// the `blitz_task::Task` trait. The actual v-table dispatch happens on
// the C side via the function pointers in `BlitzTaskVTable`. We re-declare
// the minimal subset we need here because we can't depend on `blitz_task.h`
// from Rust.

#[repr(C)]
struct BlitzTaskVTable {
    info_json: unsafe extern "C" fn(*mut CBlitzTask) -> *const c_char,
    configure: unsafe extern "C" fn(*mut CBlitzTask, *const CBlitzDataConfig) -> i32,
    set_timeout: unsafe extern "C" fn(*mut CBlitzTask, u64) -> i32,
    run: unsafe extern "C" fn(*mut CBlitzTask, CBlitzCallbacks) -> i32,
    free: Option<unsafe extern "C" fn(*mut CBlitzTask)>,
}

#[repr(C)]
struct BlitzTaskHead {
    vtable: *const BlitzTaskVTable,
}

#[repr(C)]
#[derive(Clone, Copy)]
struct CBlitzDataConfig {
    data_size_bytes: u64,
    iterations: u64,
    seed: u64,
}

#[repr(C)]
#[derive(Clone, Copy)]
struct CBlitzMetric {
    name: *const c_char,
    value: f64,
    unit: *const c_char,
    direction: i32, // BlitzDirection
    info_keys: *const *const c_char,
    info_values: *const *const c_char,
    info_len: usize,
}

type COnStatus = unsafe extern "C" fn(*mut std::ffi::c_void, i32);
type COnStart = unsafe extern "C" fn(*mut std::ffi::c_void);
type COnProgress = unsafe extern "C" fn(*mut std::ffi::c_void, *const CBlitzMetric);
type COnComplete = unsafe extern "C" fn(*mut std::ffi::c_void, *const CBlitzMetric, usize);
type COnError = unsafe extern "C" fn(*mut std::ffi::c_void, i32, *const c_char);

#[repr(C)]
#[derive(Clone, Copy)]
struct CBlitzCallbacks {
    user_data: *mut std::ffi::c_void,
    on_status: Option<COnStatus>,
    on_start: Option<COnStart>,
    on_progress: Option<COnProgress>,
    on_complete: Option<COnComplete>,
    on_error: Option<COnError>,
}

/// `CTaskAdapter` implements [`blitz_task::Task`] by dispatching to the C
/// v-table stored in the task's first field. The `TaskInfo` is fetched
/// lazily on first `info()` call and cached for the lifetime of the
/// adapter via `OnceLock`.
///
/// Public so `blitz-lib` (and any other Rust consumer) can wrap a foreign
/// `BlitzTask*` returned from a C/C++ task library's constructor and
/// drive it through the [`blitz_task::Task`] trait in-process.
pub struct CTaskAdapter {
    task: *mut CBlitzTask,
    info: OnceLock<blitz_task::TaskInfo>,
}

impl CTaskAdapter {
    /// Wrap a foreign `BlitzTask*` (as returned by a C/C++ task
    /// constructor such as `c_task_demo_new()`) so it can be driven via
    /// [`blitz_task::Task`].
    ///
    /// # Safety
    ///
    /// `task` must be a valid `*mut BlitzTask` whose first field is the
    /// task's v-table pointer (i.e. it derives from the layout declared
    /// in `blitz_task.h`). The adapter takes shared ownership: the
    /// caller must keep the task allocation alive for the lifetime of
    /// the adapter and is responsible for freeing it via
    /// `blitz_task_free` after the adapter is dropped.
    #[must_use]
    pub unsafe fn new(task: *mut CBlitzTask) -> Self {
        Self {
            task,
            info: OnceLock::new(),
        }
    }
}

unsafe impl Send for CTaskAdapter {}

impl CTaskAdapter {
    fn vtable(&self) -> *const BlitzTaskVTable {
        unsafe {
            let head = self.task as *const BlitzTaskHead;
            (*head).vtable
        }
    }

    fn fetch_info(&self) -> blitz_task::TaskInfo {
        unsafe {
            let func = (*self.vtable()).info_json;
            let ptr = func(self.task);
            if ptr.is_null() {
                panic!("blitz_task vtable.info_json returned null");
            }
            let cstr = CStr::from_ptr(ptr);
            let json = cstr.to_str().expect("TASK.json must be UTF-8");
            blitz_task::parse_task_info(json).expect("valid TASK.json")
        }
    }
}

impl blitz_task::Task for CTaskAdapter {
    fn info(&self) -> &blitz_task::TaskInfo {
        self.info.get_or_init(|| self.fetch_info())
    }

    fn run(
        &mut self,
        cb: &mut dyn blitz_task::TaskCallbacks,
    ) -> Result<Vec<blitz_task::Metric>, blitz_task::TaskError> {
        unsafe {
            let func = (*self.vtable()).run;
            // The C task only surfaces final metrics through its
            // on_complete callback. We wrap the user's callbacks in a
            // capturing shim that records the final metrics here so we
            // can return them to the Rust caller. The shim still forwards
            // every event to the user's callbacks unchanged.
            let mut captured: Vec<blitz_task::Metric> = Vec::new();
            let mut shim = CapturingCallbacks {
                inner: cb,
                captured: &mut captured,
            };
            let user_data = &mut shim as *mut CapturingCallbacks as *mut std::ffi::c_void;

            let c_cb = CBlitzCallbacks {
                user_data,
                on_status: Some(trampoline_status),
                on_start: Some(trampoline_start),
                on_progress: Some(trampoline_progress),
                on_complete: Some(trampoline_complete),
                on_error: Some(trampoline_error),
            };

            let result = func(self.task, c_cb);

            if result == 0 {
                Ok(captured)
            } else {
                Err(blitz_task::TaskError::new(
                    blitz_task::TaskErrorCode::Internal,
                    format!("C task returned non-zero ({result})"),
                ))
            }
        }
    }
}

// Capturing shim used by `CTaskAdapter::run` to record the final metrics
// passed to `on_complete` by the C side so we can return them to the
// Rust caller, while still forwarding every event to the user-supplied
// callbacks.
struct CapturingCallbacks<'a> {
    inner: &'a mut dyn blitz_task::TaskCallbacks,
    captured: &'a mut Vec<blitz_task::Metric>,
}

unsafe fn shim_from<'a>(user_data: *mut std::ffi::c_void) -> &'a mut CapturingCallbacks<'a> {
    // SAFETY: `user_data` points to a `CapturingCallbacks` that lives on
    // `CTaskAdapter::run`'s stack frame and remains valid for the
    // duration of the synchronous C-side `run` call.
    &mut *(user_data as *mut CapturingCallbacks<'_>)
}

unsafe extern "C" fn trampoline_status(user_data: *mut std::ffi::c_void, status: i32) {
    let shim = shim_from(user_data);
    let s = match status {
        0 => blitz_task::TaskStatus::Idle,
        1 => blitz_task::TaskStatus::Running,
        2 => blitz_task::TaskStatus::Completed,
        _ => blitz_task::TaskStatus::Failed,
    };
    shim.inner.on_status(s);
}

unsafe extern "C" fn trampoline_start(user_data: *mut std::ffi::c_void) {
    let shim = shim_from(user_data);
    shim.inner.on_start();
}

unsafe fn metric_from(m: &CBlitzMetric) -> blitz_task::Metric {
    let name = if m.name.is_null() {
        String::new()
    } else {
        CStr::from_ptr(m.name).to_string_lossy().into_owned()
    };
    let unit = if m.unit.is_null() {
        String::new()
    } else {
        CStr::from_ptr(m.unit).to_string_lossy().into_owned()
    };
    let direction = if m.direction == 1 {
        blitz_task::MetricDirection::LowerIsBetter
    } else {
        blitz_task::MetricDirection::HigherIsBetter
    };
    let mut info = std::collections::BTreeMap::new();
    if !m.info_keys.is_null() && !m.info_values.is_null() {
        for i in 0..m.info_len {
            let k = *m.info_keys.add(i);
            let v = *m.info_values.add(i);
            if k.is_null() || v.is_null() {
                continue;
            }
            info.insert(
                CStr::from_ptr(k).to_string_lossy().into_owned(),
                CStr::from_ptr(v).to_string_lossy().into_owned(),
            );
        }
    }
    blitz_task::Metric {
        name,
        value: m.value,
        unit,
        direction,
        info,
    }
}

unsafe extern "C" fn trampoline_progress(user_data: *mut std::ffi::c_void, m: *const CBlitzMetric) {
    if m.is_null() {
        return;
    }
    let shim = shim_from(user_data);
    let metric = metric_from(&*m);
    shim.inner.on_progress(&metric);
}

unsafe extern "C" fn trampoline_complete(
    user_data: *mut std::ffi::c_void,
    metrics: *const CBlitzMetric,
    n: usize,
) {
    let shim = shim_from(user_data);
    let mut out = Vec::with_capacity(n);
    for i in 0..n {
        out.push(metric_from(&*metrics.add(i)));
    }
    shim.inner.on_complete(&out);
    // Stash the final metrics so CTaskAdapter::run can return them.
    *shim.captured = out;
}

unsafe extern "C" fn trampoline_error(
    user_data: *mut std::ffi::c_void,
    code: i32,
    msg: *const c_char,
) {
    let shim = shim_from(user_data);
    let code = match code {
        1 => blitz_task::TaskErrorCode::Aborted,
        2 => blitz_task::TaskErrorCode::Timeout,
        3 => blitz_task::TaskErrorCode::InvalidConfig,
        4 => blitz_task::TaskErrorCode::ResourceUnavailable,
        5 => blitz_task::TaskErrorCode::Unsupported,
        6 => blitz_task::TaskErrorCode::NotImplemented,
        _ => blitz_task::TaskErrorCode::Internal,
    };
    let message = if msg.is_null() {
        String::new()
    } else {
        CStr::from_ptr(msg).to_string_lossy().into_owned()
    };
    shim.inner.on_error(&blitz_task::TaskError { code, message });
}
